   String // JSON<GrowthCharacter>\\n  portrait            String?\\n  status              String               @default(\\\"DRAFT\\\") // DRAFT, SUBMITTED, APPROVED, ACTIVE, DEAD, RETIRED\\n  backstory           CharacterBackstory?\\n  changeLogs          ChangeLog[]\\n  portraitGenerations PortraitGeneration[]\\n  personaLock         PersonaLock?\\n  godHead             GodHead?\\n  goals               Goal[]\\n  createdAt           DateTime             @default(now())\\n  updatedAt           DateTime             @updatedAt\\n\\n  @@index([entityType])\\n}\\n\\nmodel CharacterBackstory {\\n  id          String    @id @default(cuid())\\n  character   Character @relation(fields: [characterId], references: [id])\\n  characterId String    @unique\\n  responses   String // JSON: array of { prompt: string, response: string }\\n  narrative   String? // Combined/compiled narrative (generated from responses)\\n  gmNotes     String?\\n  status      String    @default(\\\"DRAFT\\\") // DRAFT, SUBMITTED, APPROVED, REVISION\\n  createdAt   DateTime  @default(now())\\n  updatedAt   DateTime  @updatedAt\\n}\\n\\nmodel Wallet {\\n  id          String  @id @default(cuid())\\n  owner       User?   @relation(fields: [ownerId], references: [id])\\n  ownerId     String? @unique\\n  walletType  String  @default(\\\"USER\\\") // USER, RESERVE, CAMPAIGN, CHARACTER, BURN, LADY_DEATH\\n  ownerType   String  @default(\\\"USER\\\") // Kept for backwards compat; walletType is canonical\\n  label       String? // Reserve: \\\"Terminal\\\",\\\"Mercy\\\",\\\"Balance\\\",\\\"Severity\\\"; System: \\\"Burn Sink\\\",\\\"Lady Death\\\"\\n  balance     BigInt  @default(0)\\n  campaignId  String? // For CAMPAIGN wallets\\n  characterId String? // For CHARACTER wallets\\n  frozen      Boolean @default(false)\\n\\n  @@index([walletType])\\n  @@index([campaignId])\\n  @@index([characterId])\\n}\\n\\nmodel KrmaTransaction {\\n  id             String   @id @default(cuid())\\n  sequenceNumber BigInt   @uniq